import React from 'react';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Container from '@mui/material/Container';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';

import AppCard from '../components/common/AppCard';
import DataTable, { Column } from '../components/common/DataTable';
import UserAlert from '../components/common/UserAlert';
import { api } from '../services/api';
import type { ImportArticlesResponse, ImportResultItem } from '../services/api';
import { useAppDispatch } from '../store/hooks';
import { showSnackbar } from '../store/slices/uiSlice';

const columns: Column<ImportResultItem>[] = [
  { key: 'index', header: '#', render: (r) => r.index },
  { key: 'ok', header: 'OK', render: (r) => (r.ok ? 'yes' : 'no') },
  { key: 'articleId', header: 'Article ID', render: (r) => r.articleId ?? '-' },
  {
    key: 'errors',
    header: 'Erreurs',
    render: (r) => (r.errors?.length ? r.errors.map((e) => `${e.field}:${e.message}`).join(' | ') : '-'),
  },
];

export default function ImportArticles() {
  const dispatch = useAppDispatch();
  const [fileName, setFileName] = React.useState<string | null>(null);
  const [busy, setBusy] = React.useState(false);
  const [error, setError] = React.useState<string | null>(null);
  const [result, setResult] = React.useState<ImportArticlesResponse | null>(null);

  const downloadFakeJson = () => {
    const items = [
      {
        title: 'Article importé - Démo 1',
        content:
          "Contenu de démonstration. ".repeat(10) +
          "Ce texte est volontairement assez long pour passer la validation (min 50 caractères).",
        excerpt: 'Résumé court pour la démo 1',
        author: 'admin',
        category: 'Actualités',
        network: 'Réseau A',
      },
      {
        title: 'Article importé - Démo 2',
        content:
          "Contenu de démonstration. ".repeat(10) +
          "Ajout de texte pour atteindre la longueur minimale.",
        excerpt: 'Résumé court pour la démo 2',
        author: 'editor',
        category: 'Tech',
        network: 'Réseau A',
      },
      {
        title: 'Article importé - Démo 3',
        content:
          "Contenu de démonstration. ".repeat(10) +
          "Encore un peu de texte pour la validation.",
        excerpt: 'Résumé court pour la démo 3',
        author: 'user',
        category: 'Culture',
        network: 'Réseau B',
      },
      {
        title: 'Article importé - Démo 4',
        content:
          "Contenu de démonstration. ".repeat(10) +
          "Article supplémentaire pour tester l'import.",
        excerpt: 'Résumé court pour la démo 4',
        author: 'admin',
        category: 'Actualités',
        network: 'Réseau A',
      },
      {
        title: 'Article importé - Démo 5',
        content:
          "Contenu de démonstration. ".repeat(10) +
          "Article supplémentaire pour tester l'import.",
        excerpt: 'Résumé court pour la démo 5',
        author: 'editor',
        category: 'Tech',
        network: 'Réseau A',
      },
    ];

    const blob = new Blob([JSON.stringify(items, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'import-articles-demo.json';
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);

    dispatch(showSnackbar({ severity: 'info', message: 'Fichier JSON de démo généré.' }));
  };

  const onFile = async (f: File) => {
    setError(null);
    setResult(null);
    setFileName(f.name);

    setBusy(true);
    try {
      const text = await f.text();
      const parsed = JSON.parse(text);
      const items = Array.isArray(parsed) ? parsed : Array.isArray(parsed?.items) ? parsed.items : null;
      if (!items) {
        setError('Format invalide: attendu un tableau JSON.');
        dispatch(showSnackbar({ severity: 'error', message: 'Format JSON invalide.' }));
        return;
      }

      const res = await api.importArticles(items);
      setResult(res);
      dispatch(showSnackbar({
        severity: res.errorCount ? 'warning' : 'success',
        message: `Import terminé: ${res.successCount} succès, ${res.errorCount} erreurs.`,
      }));
    } catch {
      setError("Impossible de lire/importer le fichier.");
      dispatch(showSnackbar({ severity: 'error', message: "Import impossible." }));
    } finally {
      setBusy(false);
    }
  };

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Stack spacing={2}>
        <Typography variant="h5">Import Articles (JSON)</Typography>
        {error ? <UserAlert severity="error" message={error} /> : null}
        {busy ? <UserAlert severity="info" message="Import en cours..." /> : null}

        <AppCard title="Uploader un fichier JSON">
          <Stack spacing={2}>
            <Stack direction={{ xs: 'column', md: 'row' }} spacing={2} alignItems={{ md: 'center' }}>
              <Button aria-label="Choisir un fichier JSON" variant="contained" component="label" disabled={busy}>
                Choisir un fichier
                <input
                  type="file"
                  accept="application/json"
                  hidden
                  onChange={(e) => {
                    const f = e.target.files?.[0];
                    if (f) void onFile(f);
                  }}
                />
              </Button>

              <Button aria-label="Générer un fichier JSON de démo" variant="outlined" onClick={downloadFakeJson} disabled={busy}>
                Générer un JSON de démo
              </Button>
            </Stack>
            <Typography variant="body2" color="text.secondary">
              {fileName ? `Fichier: ${fileName}` : 'Aucun fichier sélectionné'}
            </Typography>
            <Box sx={{ p: 2, border: '1px solid rgba(0,0,0,0.12)', borderRadius: 1, bgcolor: 'white' }}>
              <Typography variant="subtitle2">Format attendu</Typography>
              <pre style={{ margin: 0, whiteSpace: 'pre-wrap' }}>
{`[
  {
    "title": "Article importé",
    "content": "Contenu de l'article...",
    "excerpt": "Résumé",
    "author": "Auteur",
    "category": "nom-categorie",
    "network": "nom-reseau"
  }
]`}
              </pre>
            </Box>
          </Stack>
        </AppCard>

        {result ? (
          <AppCard title="Résultat import">
            <Stack spacing={1}>
              <Typography variant="body2">
                Total: {result.total} | Succès: {result.successCount} | Erreurs: {result.errorCount}
              </Typography>
              <DataTable columns={columns} rows={result.items} />
            </Stack>
          </AppCard>
        ) : null}
      </Stack>
    </Container>
  );
}
